import React, { useState, useEffect } from 'react';
import {
  Box,
  Typography,
  Paper,
  Grid,
  Card,
  CardContent,
  CardActions,
  Button,
  Chip,
  LinearProgress,
  IconButton,
  Menu,
  MenuItem,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  FormControl,
  InputLabel,
  Select,
  Alert,
  Tabs,
  Tab,
} from '@mui/material';
import {
  MoreVert as MoreVertIcon,
  Edit as EditIcon,
  Delete as DeleteIcon,
  Add as AddIcon,
  Visibility as VisibilityIcon,
  VideoCall as VideoCallIcon,
  Description as DescriptionIcon,
} from '@mui/icons-material';
import axios from 'axios';

interface Application {
  id: string;
  jobId: string;
  jobTitle: string;
  company: string;
  status: 'pending' | 'reviewed' | 'interviewed' | 'accepted' | 'rejected';
  appliedDate: string;
  lastUpdated: string;
}

interface Interview {
  id: string;
  jobId: string;
  jobTitle: string;
  company: string;
  type: 'phone' | 'video' | 'onsite';
  status: 'scheduled' | 'completed' | 'cancelled';
  date: string;
  time: string;
  duration: number;
  interviewer: string;
  meetingLink?: string;
}

const ApplicantDashboard: React.FC = () => {
  const [activeTab, setActiveTab] = useState(0);
  const [applications, setApplications] = useState<Application[]>([]);
  const [interviews, setInterviews] = useState<Interview[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [anchorEl, setAnchorEl] = useState<null | HTMLElement>(null);
  const [selectedApplication, setSelectedApplication] = useState<Application | null>(null);
  const [openDialog, setOpenDialog] = useState(false);
  const [formData, setFormData] = useState<Partial<Application>>({
    status: 'pending',
  });

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      setLoading(true);
      const [applicationsResponse, interviewsResponse] = await Promise.all([
        axios.get('/api/applications'),
        axios.get('/api/interviews'),
      ]);
      setApplications(applicationsResponse.data);
      setInterviews(interviewsResponse.data);
    } catch (err) {
      setError('Failed to fetch data');
      console.error('Error fetching data:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleTabChange = (event: React.SyntheticEvent, newValue: number) => {
    setActiveTab(newValue);
  };

  const handleMenuClick = (event: React.MouseEvent<HTMLElement>, application: Application) => {
    setAnchorEl(event.currentTarget);
    setSelectedApplication(application);
  };

  const handleMenuClose = () => {
    setAnchorEl(null);
    setSelectedApplication(null);
  };

  const handleDialogClose = () => {
    setOpenDialog(false);
    setFormData({
      status: 'pending',
    });
  };

  const handleWithdraw = async () => {
    if (selectedApplication) {
      try {
        await axios.delete(`/api/applications/${selectedApplication.id}`);
        setApplications(applications.filter(app => app.id !== selectedApplication.id));
      } catch (err) {
        setError('Failed to withdraw application');
        console.error('Error withdrawing application:', err);
      }
    }
    handleMenuClose();
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'accepted':
        return 'success';
      case 'rejected':
        return 'error';
      case 'interviewed':
        return 'info';
      case 'reviewed':
        return 'warning';
      default:
        return 'default';
    }
  };

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString();
  };

  if (loading) {
    return <LinearProgress />;
  }

  if (error) {
    return <Alert severity="error">{error}</Alert>;
  }

  return (
    <Box sx={{ p: 3 }}>
      <Typography variant="h4" gutterBottom>
        My Applications
      </Typography>

      <Tabs value={activeTab} onChange={handleTabChange} sx={{ mb: 3 }}>
        <Tab label="Applications" />
        <Tab label="Interviews" />
      </Tabs>

      {activeTab === 0 && (
        <Grid container spacing={3}>
          {applications.map((application) => (
            <Grid item xs={12} sm={6} key={application.id}>
              <Card>
                <CardContent>
                  <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                    <Typography variant="h6" component="div">
                      {application.jobTitle}
                    </Typography>
                    <IconButton
                      size="small"
                      onClick={(e) => handleMenuClick(e, application)}
                    >
                      <MoreVertIcon />
                    </IconButton>
                  </Box>
                  <Typography color="text.secondary" gutterBottom>
                    {application.company}
                  </Typography>
                  <Box sx={{ display: 'flex', gap: 1, mb: 2 }}>
                    <Chip
                      label={application.status}
                      size="small"
                      color={getStatusColor(application.status)}
                    />
                  </Box>
                  <Box sx={{ display: 'flex', justifyContent: 'space-between' }}>
                    <Typography variant="body2">
                      Applied: {formatDate(application.appliedDate)}
                    </Typography>
                    <Typography variant="body2">
                      Updated: {formatDate(application.lastUpdated)}
                    </Typography>
                  </Box>
                </CardContent>
                <CardActions>
                  <Button size="small" startIcon={<VisibilityIcon />}>
                    View Details
                  </Button>
                </CardActions>
              </Card>
            </Grid>
          ))}
        </Grid>
      )}

      {activeTab === 1 && (
        <Grid container spacing={3}>
          {interviews.map((interview) => (
            <Grid item xs={12} sm={6} key={interview.id}>
              <Card>
                <CardContent>
                  <Typography variant="h6" component="div">
                    {interview.jobTitle}
                  </Typography>
                  <Typography color="text.secondary" gutterBottom>
                    {interview.company}
                  </Typography>
                  <Box sx={{ display: 'flex', gap: 1, mb: 2 }}>
                    <Chip
                      label={interview.type}
                      size="small"
                      color="primary"
                    />
                    <Chip
                      label={interview.status}
                      size="small"
                      color={interview.status === 'completed' ? 'success' : 'default'}
                    />
                  </Box>
                  <Box sx={{ display: 'flex', flexDirection: 'column', gap: 1 }}>
                    <Typography variant="body2">
                      Date: {formatDate(interview.date)}
                    </Typography>
                    <Typography variant="body2">
                      Time: {interview.time}
                    </Typography>
                    <Typography variant="body2">
                      Duration: {interview.duration} minutes
                    </Typography>
                    <Typography variant="body2">
                      Interviewer: {interview.interviewer}
                    </Typography>
                  </Box>
                </CardContent>
                <CardActions>
                  {interview.meetingLink && (
                    <Button
                      size="small"
                      startIcon={<VideoCallIcon />}
                      href={interview.meetingLink}
                      target="_blank"
                    >
                      Join Meeting
                    </Button>
                  )}
                  <Button size="small" startIcon={<DescriptionIcon />}>
                    View Details
                  </Button>
                </CardActions>
              </Card>
            </Grid>
          ))}
        </Grid>
      )}

      <Menu
        anchorEl={anchorEl}
        open={Boolean(anchorEl)}
        onClose={handleMenuClose}
      >
        <MenuItem onClick={handleWithdraw}>
          <DeleteIcon sx={{ mr: 1 }} /> Withdraw Application
        </MenuItem>
      </Menu>
    </Box>
  );
};

export default ApplicantDashboard;
